import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import {
  Button,
  Select,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  useViewMobileLayout,
} from '@linm-soft/common-components';
import { SearchInput } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { LedgerEntryDto } from '../../../services/kt/models';
import { createAccountSearchConfig, useAccountSearchAsOfDate } from '../../../components/search';
import { formatAccountDisplay } from '../../../components/search/accountSearchApi';
import { reportPageLabels } from '../../../constants/reportPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import { MONTH_OPTIONS, yearOptions } from '../../../constants/voucher';
import { LedgerReportGrid } from '../../../components/report';
import {
  getSoChiTietPageSession,
  reportPageSessionKey,
  saveSoChiTietPageSession,
} from '../../../components/report/reportPageSessionCache';
import {
  patchReportFilterFieldError,
  scrollToFirstReportFilterField,
  validateRequiredTrimmed,
  type ReportFilterFieldRef,
} from '../../../utils/reportFilterValidation';
import {
  getReportGridRowMenuHintMessage,
  reportGridRowHintDismissStorageKey,
} from '../../../utils/reportGridRowMenuHint';
import { useReportAccountFilterDefault } from '../../../hooks/useReportAccountFilterDefault';

const labels = reportPageLabels.soChiTiet;
const TEST_ID = 'erp-so-chi-tiet';
const PAGE_ID = 'kt-so-chi-tiet';

const SO_CHI_TIET_FILTER_FIELDS: readonly ReportFilterFieldRef[] = [
  { errorKey: 'accountCode', fieldSuffix: 'account' },
];

type SoChiTietFilterErrors = {
  accountCode?: string;
};

const SoChiTietPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const location = useLocation();
  const viewMobile = useViewMobileLayout();
  const rowMenuHintMessage = viewMobile ? labels.rowMenuHintTouch : labels.rowMenuHint;
  const sessionKey = reportPageSessionKey(location.pathname, location.search);
  const now = new Date();
  const cached = getSoChiTietPageSession(sessionKey);

  const [month, setMonth] = useState(cached?.month ?? String(now.getMonth() + 1));
  const [year, setYear] = useState(cached?.year ?? String(now.getFullYear()));
  const [accountCode, setAccountCode] = useState(cached?.accountCode ?? '');
  const [accountName, setAccountName] = useState(cached?.accountName ?? '');
  useReportAccountFilterDefault('kt-so-chi-tiet-report', cached?.accountCode, accountCode, setAccountCode, setAccountName);
  const [items, setItems] = useState<LedgerEntryDto[]>(cached?.items ?? []);
  const [loading, setLoading] = useState(false);
  const [filterErrors, setFilterErrors] = useState<SoChiTietFilterErrors>({});
  const { showTableLoading } = useCatalogTableBusy(loading);

  const fromDate = `${year}-${month.padStart(2, '0')}-01`;
  const accountSearchOptions = useAccountSearchAsOfDate(fromDate, 'all');
  const accountSearchConfig = useMemo(
    () => createAccountSearchConfig(accountSearchOptions),
    [accountSearchOptions],
  );
  const lastDay = new Date(Number(year), Number(month), 0).getDate();
  const toDate = `${year}-${month.padStart(2, '0')}-${lastDay}`;

  useEffect(() => {
    saveSoChiTietPageSession(sessionKey, { month, year, accountCode, accountName, items });
  }, [sessionKey, month, year, accountCode, accountName, items]);

  const validateFilters = useCallback((): SoChiTietFilterErrors => {
    const errors: SoChiTietFilterErrors = {};
    const accountError = validateRequiredTrimmed(accountCode, labels.accountRequired);
    if (accountError) errors.accountCode = accountError;
    return errors;
  }, [accountCode]);

  const handleLoad = useCallback(async () => {
    const errors = validateFilters();
    if (Object.keys(errors).length > 0) {
      setFilterErrors(errors);
      scrollToFirstReportFilterField(TEST_ID, SO_CHI_TIET_FILTER_FIELDS, errors);
      dispatchAppToast(dispatch, { message: labels.filterValidationSummary, type: 'warning' });
      return;
    }
    setFilterErrors({});
    setLoading(true);
    try {
      const data = await ktService.getAccountDetailLedger({ accountCode, fromDate, toDate });
      const list = (data as { lines?: LedgerEntryDto[] })?.lines ?? (Array.isArray(data) ? data : []);
      setItems(list);
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, labels.loadError), type: 'error' });
    } finally {
      setLoading(false);
    }
  }, [accountCode, fromDate, toDate, dispatch, validateFilters, labels.filterValidationSummary]);

  const hasData = items.length > 0;

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-month`,
        content: (
          <Select value={month} onChange={e => setMonth(e.target.value)} options={MONTH_OPTIONS} />
        ),
      },
      {
        testId: `${TEST_ID}-field-year`,
        content: (
          <Select value={year} onChange={e => setYear(e.target.value)} options={yearOptions()} />
        ),
      },
      {
        testId: `${TEST_ID}-field-account`,
        content: (
          <div className={erp.field}>
            <SearchInput
              config={accountSearchConfig}
              value={accountCode}
              primaryDisplay={formatAccountDisplay(accountCode, accountName)}
              label={labels.fieldAccount}
              required
              error={filterErrors.accountCode}
              onChange={a => {
                patchReportFilterFieldError(setFilterErrors, 'accountCode');
                setAccountCode(a.code);
                setAccountName(a.name);
              }}
              onClear={() => {
                patchReportFilterFieldError(setFilterErrors, 'accountCode');
                setAccountCode('');
                setAccountName('');
              }}
              showSecondaryInput={false}
              placeholder={labels.accountPlaceholder}
            />
          </div>
        ),
      },
      {
        testId: `${TEST_ID}-view-btn`,
        content: (
          <Button variant="primary" onClick={handleLoad} loading={loading} data-testid={`${TEST_ID}-view-btn`}>
            {labels.view}
          </Button>
        ),
      },
    ],
    [month, year, accountCode, accountName, accountSearchConfig, filterErrors.accountCode, handleLoad, loading],
  );

  const reportToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: handleLoad,
      canChart: false,
      canPrint: hasData,
      onPrint: () => window.print(),
    }),
    [handleLoad, hasData],
  );

  const listBody = !showTableLoading && items.length === 0 ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>{labels.empty}</div>
  ) : !showTableLoading ? (
    <LedgerReportGrid
      items={items}
      labels={labels}
      testIdPrefix={TEST_ID}
      page={1}
      pageSize={Math.max(items.length, 1)}
      exportAccountCode={accountCode}
      showBalance={false}
      reportTitle={labels.title}
      onRefresh={handleLoad}
      getRowMenuHintMessage={getReportGridRowMenuHintMessage(rowMenuHintMessage)}
      rowMenuHintDismissStorageKey={reportGridRowHintDismissStorageKey(TEST_ID)}
    />
  ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="report"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-list-alt',
          pageId: PAGE_ID,
        }}
        reportToolbar={reportToolbar}
        listTitle={labels.title}
        listRowMenuHelp
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default SoChiTietPage;
